const source = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const assets = source.n8nBinaryAssets || {};
const binary = {};
for (const [fieldName, asset] of Object.entries(assets)) {
  if (!asset || !asset.data || !asset.mimeType) continue;
  binary[fieldName] = {
    data: String(asset.data).replace(/^data:[^;]+;base64,/, ''),
    mimeType: asset.mimeType,
    fileName: asset.fileName || fieldName,
  };
}
const inputBinaryFields = Object.keys(binary)
  .filter((field) => field === 'base_canvas' || /^asset_\d+$/.test(field))
  .sort((a, b) => {
    if (a === 'base_canvas') return -1;
    if (b === 'base_canvas') return 1;
    return Number(a.replace(/\D/g, '')) - Number(b.replace(/\D/g, ''));
  });
return [{ json: { ...source, inputBinaryFields }, binary }];
